import React from 'react';
import { Link } from 'react-router-dom';
import { FaCalendarAlt, FaBuilding, FaInfoCircle, FaArrowRight } from 'react-icons/fa';
import formatDate from '../utils/formatDate';

const SchemeCard = ({ scheme }) => {
  const {
    _id,
    name,
    description,
    department,
    lastDate,
    category
  } = scheme;

  // Truncate description if it's too long
  const truncateText = (text, maxLength = 150) => {
    if (!text) return '';
    if (text.length <= maxLength) return text;
    return text.substring(0, maxLength) + '...';
  };

  // Determine the badge color based on category
  const getBadgeColor = (category) => {
    switch (category?.toLowerCase()) {
      case 'subsidy':
        return 'bg-green-100 text-green-800';
      case 'loan':
        return 'bg-blue-100 text-blue-800';
      case 'insurance':
        return 'bg-purple-100 text-purple-800';
      case 'grant':
        return 'bg-yellow-100 text-yellow-800';
      case 'certification':
        return 'bg-orange-100 text-orange-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  // Check if scheme has expired
  const isExpired = lastDate && new Date(lastDate) < new Date();

  return (
    <div className="bg-white rounded-lg shadow-md p-5 mb-4 hover:shadow-lg transition-shadow">
      <div className="flex justify-between items-start mb-3">
        <h3 className="text-xl font-semibold text-gray-800">{name}</h3>
        {category && (
          <span className={`text-xs font-medium px-2.5 py-0.5 rounded ${getBadgeColor(category)}`}>
            {category}
          </span>
        )}
      </div>
      
      <p className="text-gray-600 mb-4">{truncateText(description)}</p>
      
      <div className="flex flex-wrap gap-y-2 text-sm text-gray-500 mb-4">
        {department && (
          <div className="flex items-center mr-4">
            <FaBuilding className="mr-1 text-gray-400" />
            <span>{department}</span>
          </div>
        )}
        
        {lastDate && (
          <div className="flex items-center">
            <FaCalendarAlt className="mr-1 text-gray-400" />
            <span className={isExpired ? 'text-red-500' : ''}>
              {isExpired ? 'Expired: ' : 'Last Date: '}
              {formatDate(lastDate)}
            </span>
          </div>
        )}
      </div>
      
      <div className="flex justify-between items-center mt-4 pt-3 border-t border-gray-100">
        {isExpired ? (
          <span className="text-red-500 font-medium">Application closed</span>
        ) : (
          <span className="text-green-600 font-medium">Active</span>
        )}
        
        <Link 
          to={`/schemes/${_id}`}
          className="inline-flex items-center text-green-600 hover:text-green-800 font-medium"
        >
          View Details
          <FaArrowRight className="ml-1 h-4 w-4" />
        </Link>
      </div>
    </div>
  );
};

export default SchemeCard;
